package com.hospital.management.controller.admission;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.RoomServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/admin/rooms")public class RoomListServlet extends HttpServlet{private final RoomService s;public RoomListServlet(){this(new RoomServiceImpl());}public RoomListServlet(RoomService x){s=x;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{int p=Math.max(1,AdmissionRequest.number(q.getParameter("page"),1)),z=Math.max(1,AdmissionRequest.number(q.getParameter("size"),10));q.setAttribute("roomPage",s.listRooms(new PageRequest(p,z,q.getParameter("search")),AdmissionRequest.id(q.getParameter("departmentId")),q.getParameter("roomType"),q.getParameter("status")));q.getRequestDispatcher("/WEB-INF/views/admin/rooms/list.jsp").forward(q,r);}}
